import{_ as a,o,c as n,a2 as t}from"./chunks/framework.BYlK8ftn.js";const m=JSON.parse('{"title":"0005 — Win goal: conquer the worlds + renewable caravan economy","description":"","frontmatter":{},"headers":[],"relativePath":"decisions/0005-win-goal-conquest.md","filePath":"decisions/0005-win-goal-conquest.md","lastUpdated":1782033505000}'),r={name:"decisions/0005-win-goal-conquest.md"};function l(s,e,i,c,d,u){return o(),n("div",null,[...e[0]||(e[0]=[t('<h1 id="_0005-—-win-goal-conquer-the-worlds-renewable-caravan-economy" tabindex="-1">0005 — Win goal: conquer the worlds + renewable caravan economy <a class="header-anchor" href="#_0005-—-win-goal-conquer-the-worlds-renewable-caravan-economy" aria-label="Permalink to &quot;0005 — Win goal: conquer the worlds + renewable caravan economy&quot;">​</a></h1><ul><li>Status: Accepted (design); implementation tracked under FLO-450 children</li><li>Date: 2026-06-21</li><li>Deciders: Daedalus (CTO), per board feedback FLO-450</li></ul><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Player feedback (FLO-450): the game ends the moment you raid <strong>3 caravans</strong> (<code>OBJECTIVE_CARAVAN_TARGET = 3</code>, <code>objectiveMachine.evaluateOutcome</code>). That is an instant, shallow win that fires <em>before</em> the economy can be played:</p><ul><li>All three prosthetics cost <strong>260 gold</strong> total (hand 80 + leg 120 + eye 60).</li><li>A caravan drops only <strong>~19 gold expected</strong> (loot table: 3 rolls, gold weight 50/120, 5–25 per roll).</li><li>Caravans <strong>do not respawn</strong> — once a zone&#39;s anchors are looted, the gold faucet is dry.</li></ul><p>So a player literally cannot farm enough gold to try the prosthetics before the run is declared won. &quot;Victory&quot; is also undefined as a long-term goal — the board asked for a real far goal: <em>pass all the worlds, rob all the caravans.</em></p><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>Replace the flat 3-caravan win with a <strong>data-driven world-conquest campaign</strong> and make the caravan economy <strong>renewable</strong>.</p><h3 id="_1-win-conquer-every-available-world" tabindex="-1">1. Win = conquer every available world <a class="header-anchor" href="#_1-win-conquer-every-available-world" aria-label="Permalink to &quot;1. Win = conquer every available world&quot;">​</a></h3><ul><li>A <strong>world is conquered</strong> when caravans raided in it reach that world&#39;s <strong>quota</strong>. Quotas: <code>forest 3</code>, <code>human-lands 5</code>, <code>empire 6</code>, <code>mountains 8</code>.</li><li><strong>Victory = every world whose <code>status === &#39;available&#39;</code> is conquered.</strong> The win logic reads <code>ZONES</code> — it is <em>data-driven</em>, not a hardcoded count. Today that means conquering <strong>forest + human-lands</strong> (8 caravans) wins. When empire and mountains ship (flip to <code>available</code>), the goal auto-extends to all four with no win-logic change. This honours &quot;pass all the worlds&quot; while staying shippable now.</li><li>Worlds unlock <strong>sequentially</strong>; locked worlds (empire, mountains) render on the world map as <strong>&quot;Coming soon&quot;</strong> and do not block the achievable victory.</li></ul><h3 id="_2-caravans-respawn" tabindex="-1">2. Caravans respawn <a class="header-anchor" href="#_2-caravans-respawn" aria-label="Permalink to &quot;2. Caravans respawn&quot;">​</a></h3><ul><li>After a caravan is looted and defeated, its anchor <strong>re-arms a fresh caravan after <code>CARAVAN_RESPAWN_MS</code> (60 s)</strong>. The zone stays huntable → gold is renewable.</li><li>Raids beyond a world&#39;s quota don&#39;t advance conquest but <strong>still drop loot/gold</strong> (pure farming). Respawn is anchor-capped — never more live caravans than the zone&#39;s original anchor count.</li></ul><h3 id="_3-economy-retune" tabindex="-1">3. Economy retune <a class="header-anchor" href="#_3-economy-retune" aria-label="Permalink to &quot;3. Economy retune&quot;">​</a></h3><ul><li>Bump the gold entry so a haul isn&#39;t &quot;скудно&quot;: <strong>weight 60, min 10, max 40</strong> (expected ≈ <strong>35 gold/caravan</strong>, up from ~19). Prosthetic prices stay (they are meaningful sinks).</li><li>Result: conquering two worlds (~8 caravans ≈ 280 g) already affords all prosthetics mid-campaign, and respawn farming covers experimentation. A balance unit test pins this invariant: expected gold over the available-world quota ≥ sum of prosthetic prices.</li></ul><h3 id="state-save-model" tabindex="-1">State &amp; save model <a class="header-anchor" href="#state-save-model" aria-label="Permalink to &quot;State &amp; save model&quot;">​</a></h3><ul><li>Track caravans raided <strong>per zone</strong> (<code>Record&lt;ZoneId, number&gt;</code>); derive <code>conqueredZones</code> (count ≥ quota) and sequential <code>unlockedZones</code>.</li><li><code>objectiveMachine</code> takes per-zone progress + quotas; <code>evaluateOutcome</code> returns <code>won</code> when all available zones are conquered. Stays a pure, exhaustively-tested function.</li><li>Save migration adds the per-zone map (default <code>{}</code>); old saves migrate without data loss (the legacy flat <code>caravansRaided</code> is informational only).</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><ul><li><strong>Boring/reversible:</strong> all behaviour is constants + a pure decision function + a Redux slice. No new moving parts in the deployment story.</li><li><strong>Schema:</strong> the save format gains a per-zone map → a versioned migration, with fixture coverage (schema-is-forever lens).</li><li><strong>Content roadmap (not in this change):</strong> the full four-world far goal needs the empire &amp; mountains <strong>scenes</strong> built. Those are follow-up content epics; when each lands and flips <code>available</code>, the win goal extends automatically.</li><li><strong>Trust-the-boundary:</strong> quotas/respawn validated once in the slice/scene edge, then trusted by the pure machine.</li></ul><h2 id="implementation-flo-450-children" tabindex="-1">Implementation (FLO-450 children) <a class="header-anchor" href="#implementation-flo-450-children" aria-label="Permalink to &quot;Implementation (FLO-450 children)&quot;">​</a></h2><ul><li>Core conquest win + state + save migration + objective HUD → Wayland.</li><li>Caravan respawn → Aldric.</li><li>Economy retune + balance test → Soren.</li></ul>',20)])])}const g=a(r,[["render",l]]);export{m as __pageData,g as default};
